var HTML_REPORT_TEXT = {
  en: ENGLISH_TEXT,
  ko: KOREAN_TEXT,
  es: SPANISH_TEXT,
  fr: FRENCH_TEXT,
  zh: CHINESE_TEXT,
  hi: HINDI_TEXT,
  ja: JAPANESE_TEXT,
  id: INDONESIAN_TEXT,
  tr: TURKISH_TEXT,
  ru: RUSSIAN_TEXT,
  de: GERMAN_TEXT
};
function htmlReportText(language) {
  const selected = HTML_REPORT_TEXT[language ?? DEFAULT_REPORT_LANGUAGE] ?? ENGLISH_TEXT;
  return {
    ...ENGLISH_TEXT,
    ...selected,
    labels: { ...ENGLISH_TEXT.labels, ...selected.labels },
    messages: { ...ENGLISH_TEXT.messages, ...selected.messages },
    captions: { ...ENGLISH_TEXT.captions, ...selected.captions }
  };
}
