function dependencyProvenance(input) {
  return input.graph.nodes.map((node) => ({
    packageId: node.id,
    purl: packageUrl(node),
    origins: displayDependencyOrigins(input.project, node)
  })).sort((left, right) => left.purl.localeCompare(right.purl));
}
function displayDependencyOrigins(project, node) {
  const origins = node.origins && node.origins.length > 0 ? node.origins.map((origin) => ({
    kind: origin.lockfileKind,
    path: displayProjectPath(project.rootDir, origin.lockfilePath)
  })) : [{
    kind: project.lockfile.kind,
    path: displayLockfilePath(project)
  }];
  const uniqueOrigins2 = new Map;
  for (const origin of origins) {
    uniqueOrigins2.set(`${origin.kind}\x00${origin.path}`, origin);
  }
  return [...uniqueOrigins2.values()].sort((left, right) => left.path.localeCompare(right.path) || left.kind.localeCompare(right.kind));
}
function displayLockfileSummary(project) {
  return displayLockfiles(project).map((lockfile) => `${lockfile.path} (${lockfile.kind})`).join(", ");
}
function renderAdditionalLockfileLines(project) {
  const lockfiles = displayLockfiles(project);
  return lockfiles.length > 1 ? [`Lockfiles: ${lockfiles.map((lockfile) => `${lockfile.path} (${lockfile.kind})`).join(", ")}`] : [];
}
function renderAdditionalMarkdownLockfileLines(project) {
  const lockfiles = displayLockfiles(project);
  return lockfiles.length > 1 ? [`- Lockfiles: ${lockfiles.map((lockfile) => `${formatMarkdownInlineCode(lockfile.path)} (${formatMarkdownInlineCode(lockfile.kind)})`).join(", ")}`] : [];
}
function displayLockfiles(project) {
  return projectLockfiles(project).map((lockfile) => ({
    kind: lockfile.kind,
    path: displayProjectPath(project.rootDir, lockfile.path)
  }));
}
function disabledPolicySummary() {
  return {
    enabled: false,
    sourceFiles: [],
    allowLicenseCount: 0,
    denyLicenseCount: 0,
    severityOverrideCount: 0,
    packageRuleCount: 0,
    profileCount: 0,
    profileOverrideCount: 0,
    allowedRegistryHostCount: 0,
    registryAuthHostCount: 0
  };
}
function displayProjectPath(projectRoot, targetPath) {
  const relativePath = path77.relative(projectRoot, targetPath);
  if (relativePath && !relativePath.startsWith("..") && !path77.isAbsolute(relativePath)) {
    return relativePath.replace(/\\/g, "/");
  }
  return path77.basename(targetPath);
}
function displayLockfilePath(project) {
  return displayProjectPath(project.rootDir, project.lockfile.path);
}
function displayLockfileDirectoryPath(project) {
  const directoryPath = path77.dirname(displayLockfilePath(project));
  return directoryPath === "" ? "." : directoryPath;
}
function markdownProjectLabel(input) {
  return input.graph.rootName ?? ".";
}
function buildWaiverDriftSummary(input) {
  if (!input.strictWaivers) {
    return {};
  }
  const waiverDriftCount = input.expiredWaivers.length + input.unmatchedWaivers.length;
  return {
    strictWaivers: true,
    waiverDriftFailed: waiverDriftCount > 0,
    waiverDriftCount
  };
}
function buildScanSummary(input) {
  const directCount = input.graph.nodes.filter((node) => node.direct).length;
  const transitiveCount = input.graph.nodes.length - directCount;
  const evidenceFileCount = input.evidence.reduce((sum, item) => sum + item.files.length, 0);
  const evidenceWarningCount = input.evidence.reduce((sum, item) => sum + item.warnings.length, 0);
  const licenseSummary = summarizeLicenses(input.normalizedLicenses);
  return {
    dependencyGraph: {
      total: input.graph.nodes.length,
      direct: directCount,
      transitive: transitiveCount
    },
    evidence: {
      packages: input.evidence.length,
      files: evidenceFileCount,
      warnings: evidenceWarningCount
    },
    licenses: {
      highConfidence: licenseSummary.high,
      mediumConfidence: licenseSummary.medium,
      lowConfidence: licenseSummary.low,
      missing: licenseSummary.missing,
      malformed: licenseSummary.malformed
    },
    risks: summarizeRiskFindings(input.riskFindings),
    waivers: {
      applied: input.waivedFindings.length,
      expired: input.expiredWaivers.length,
      unmatched: input.unmatchedWaivers.length
    }
  };
}
